import React from 'react';
import Container from '@mui/material/Container';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import DataTable, { Column } from '../components/common/DataTable';
import UserAlert from '../components/common/UserAlert';
import { api } from '../services/api';
import type { Network } from '../types/entities';

type Row = Network;

const columns: Column<Row>[] = [
  { key: 'id', header: 'ID', render: (r) => r.id },
  { key: 'name', header: 'Nom', render: (r) => r.name },
  { key: 'description', header: 'Description', render: (r) => r.description },
];

export default function NetworksList() {
  const [rows, setRows] = React.useState<Network[]>([]);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    let mounted = true;
    api
      .listNetworks()
      .then((data) => {
        if (!mounted) return;
        setRows(data);
      })
      .catch(() => {
        if (!mounted) return;
        setError('Impossible de charger les réseaux.');
      });

    return () => {
      mounted = false;
    };
  }, []);

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        <Typography variant="h5">Réseaux</Typography>
        {error ? <UserAlert severity="error" message={error} /> : null}
        <DataTable columns={columns} rows={rows} />
      </Stack>
    </Container>
  );
}
